package github.chains;

import com.github.javaparser.*;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.visitor.ModifierVisitor;
import com.github.javaparser.ast.visitor.Visitable;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        Path sourcePath = Paths.get(sourceDirectory);

        if (!Files.exists(sourcePath)) {
            System.err.println("Source directory does not exist: " + sourceDirectory);
            System.exit(1);
        }

        // Process all Java files in the directory
        Files.walk(sourcePath)
                .filter(path -> path.toString().endsWith(".java"))
                .forEach(Main::processJavaFile);
    }

    private static void processJavaFile(Path javaFilePath) {
        try {
            // Read the Java file
            String content = Files.readString(javaFilePath);

            // Parse the Java file
            Optional<CompilationUnit> cu = JavaParser.parse(content);

            if (cu.isPresent()) {
                CompilationUnit compilationUnit = cu.get();

                // Create a visitor to transform imports
                ImportTransformer visitor = new ImportTransformer();
                compilationUnit.accept(visitor, null);

                // Write back the modified content
                String modifiedContent = compilationUnit.toString();
                Files.writeString(javaFilePath, modifiedContent);

                System.out.println("Processed: " + javaFilePath);
            }
        } catch (Exception e) {
            System.err.println("Error processing file " + javaFilePath + ": " + e.getMessage());
        }
    }

    // Transformer that replaces javax.mvc imports with jakarta.mvc
    private static class ImportTransformer extends ModifierVisitor<Void> {
        @Override
        public Visitable visit(ImportDeclaration importDecl, Void arg) {
            // Check if this is a javax.mvc import
            if (importDecl.getNameAsString().startsWith("javax.mvc")) {
                // Replace with jakarta.mvc
                String newImport = importDecl.getNameAsString().replace("javax.mvc", "jakarta.mvc");
                importDecl.setName(newImport);
            }
            return super.visit(importDecl, arg);
        }
    }
}

